                const _senMap = {};
                try {
                    const _oldFirst = (typeof window.getDivisionAgeOrder === 'function')
                        ? window.getDivisionAgeOrder(Object.keys(divisions || {}))
                        : Object.keys(divisions || {});
                    const _N = _oldFirst.length;
                    _oldFirst.forEach(function (nm, i) { _senMap[nm] = _N - 1 - i; }); // oldest gets the highest score
                } catch (_eS) {}
                const _sen = function (gr) { const v = _senMap[gr]; return (v == null) ? -1 : v; };
                let moved = 0;
                Object.keys(sa).sort(function (a, b) { return _sen(bunkGrade[String(b)]) - _sen(bunkGrade[String(a)]); }).forEach(function (b) {
                    const bs = String(b), grade = bunkGrade[bs];
                    (sa[b] || []).forEach(function (s) {
                        if (!s || s.continuation || !s.field || s.field === 'Free') return;
                        // Forced-pair lock: never move a paired half (Phase A would
                        // otherwise drag one half of a pair to a better-ranked field
                        // in the group and split the co-location).
                        if (s._pairLock) return;
                        const cur = fgMap[s.field]; if (!cur) return;
                        const sport = s._activity; if (!sport) return;
                        const st = (s._startMin != null ? s._startMin : s.startMin), en = (s._endMin != null ? s._endMin : s.endMin);
                        if (st == null || en == null) return;
                        const members = fgGroups[cur.group];
                        for (let i = 0; i < members.length; i++) {
                            const m = members[i];
                            if (m.rank >= cur.rank) break;                                       // only strictly better-ranked
                            if (m.name === s.field) continue;
                            if ((hostsBySport[sport] || []).indexOf(m.name) < 0) continue;        // field must host the sport
                            if (!canUse(m.name, st, en, bs, grade, sport)) continue;               // capacity/sharing OK
                            if (_validateWritePlacement(m.name, sport, grade, bs, st, en)) continue; // access/time problem → skip
                            const from = s.field;
                            s.field = m.name; s._fqMoved = true;
                            const fl = occ[from];
                            if (fl) { for (let k = 0; k < fl.length; k++) { if (fl[k].bunk === bs && fl[k].s === st && fl[k].e === en) { fl.splice(k, 1); break; } } }
                            (occ[m.name] = occ[m.name] || []).push({ s: st, e: en, bunk: bs, act: sport });
                            moved++;
                            break;
                        }
                    });
                });
                // PHASE B — seniority re-pair: within each (group, exact time window),
